import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetime, timedeltaimport urllib.parseimport plotly.express as pximport warnings# Gereksiz uyarıları gizlewarnings.filterwarnings("ignore")# --- 1. SAYFA AYARLARI ---st.set_page_config(    page_title="Bostanlı Çözüm VIP",     layout="wide",     page_icon="🏫",    initial_sidebar_state="collapsed" )# Arayüz temizleme ve Üst Menü Tasarımı (CSS)st.markdown("""    <style>    #MainMenu {visibility: hidden;}    footer {visibility: hidden;}    header {visibility: hidden;}    .stDeployButton {display:none;}    .stTabs [data-baseweb="tab-list"] {        gap: 10px;        background-color: #f0f2f6;        padding: 10px;        border-radius: 10px;    }    .stTabs [data-baseweb="tab"] {        height: 50px;        white-space: pre-wrap;        background-color: #ffffff;        border-radius: 5px;        padding: 10px 20px;        font-weight: bold;    }    </style>    """, unsafe_allow_html=True)# --- 2. ŞİFRE SİSTEMİ ---def check_password():    if "password_correct" not in st.session_state:        st.title("🔐 Kurumsal Yönetim Paneli")        pwd = st.text_input("Giriş Şifresi", type="password")        if st.button("Sisteme Giriş Yap"):            if pwd == "cozum35":                st.session_state["password_correct"] = True                st.rerun()            else:                st.error("❌ Hatalı şifre.")        return False    return Trueif check_password():    conn = st.connection("gsheets", type=GSheetsConnection)    def wa_link(tel, mesaj):        tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")        if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]        elif not tel_str.startswith("90"): tel_str = "90" + tel_str        return f"https://wa.me/{tel_str}?text={urllib.parse.quote(mesaj)}"    # --- 3. ÜST MENÜ (TABS) ---    st.title("🏫 Bostanlı Çözüm VIP Yönetim")    t1, t2, t3, t4 = st.tabs(["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "📊 Kurucu Raporu", "📈 Gelişmiş Analiz"])    # --- 📞 TAB 1: VELİ GÖRÜŞMELERİ ---    with t1:        st.header("📞 Veli Görüşme Kayıt")        try:            df_v = conn.read(worksheet="gorusmeler", ttl=0)        except:            df_v = pd.DataFrame(columns=["Tarih", "Ad Soyad", "Telefon", "Konu", "Durum", "Notlar"])                with st.form("v_form", clear_on_submit=True):            # TARİH SEÇİMİ EKLENDİ            v_tarih = st.date_input("Görüşme Tarihi", datetime.now())            c1, c2 = st.columns(2)            v_ad = c1.text_input("Veli / Öğrenci Ad Soyad")            v_tel = c1.text_input("Telefon Numarası")            v_konu = c2.selectbox("Konu", ["Yeni Kayıt", "YKS Hazırlık", "LGS Hazırlık", "Rehberlik", "Taksit", "Diğer"])            v_durum = c2.selectbox("Durum", ["Beklemede", "Olumlu", "Kayıt Tamamlandı", "İptal"])            v_not = st.text_area("Görüşme Notları")                        if st.form_submit_button("Kaydı Tamamla"):                if v_ad and v_tel:                    new = pd.DataFrame([{"Tarih": v_tarih.strftime("%Y-%m-%d"), "Ad Soyad": v_ad, "Telefon": v_tel, "Konu": v_konu, "Durum": v_durum, "Notlar": v_not}])                    conn.update(worksheet="gorusmeler", data=pd.concat([df_v, new], ignore_index=True))                    st.success(f"✅ {v_ad} için {v_tarih} tarihli kayıt tamamlandı.")                    st.markdown(f'[(🟢 WhatsApp Mesajı Gönder)]({wa_link(v_tel, "Sayın " + v_ad + ", görüşmemiz için teşekkür ederiz.")})')    # --- 💰 TAB 2: KASA İŞLEMLERİ ---    with t2:        st.header("💰 Kasa Giriş / Çıkış")        try:            df_k = conn.read(worksheet="kasa", ttl=0)        except:            df_k = pd.DataFrame(columns=["Tarih", "Tip", "Kategori", "Miktar", "Detay"])        # TARİH SEÇİMİ EKLENDİ        k_tarih = st.date_input("İşlem Tarihi", datetime.now())        k_tip = st.radio("İşlem Türü Seçiniz:", ["Gelir (Tahsilat)", "Gider (Ödeme)"], horizontal=True)                if k_tip == "Gelir (Tahsilat)":            k_kalemler = ["Aidat Ödemesi", "Yayın Paketi Ödemesi", "Özel Ders Ödemesi", "Deneme Kulübü Ödemesi", "Kamp Ödemesi", "Diğer Gelir"]        else:            k_kalemler = ["Kira", "Maaş", "Deneme Ücreti", "Kargo", "Elektrik", "Su", "İnternet", "Sabit Telefon", "Cep Telefonu", "Market Alışverişi", "Reklam", "Diğer Gider"]                    k_kat = st.selectbox("Kategori Seçin", k_kalemler)        k_tutar = st.number_input("Tutar (TL)", min_value=0.0, step=10.0)        k_detay = st.text_input("Açıklama (Örn: Mart Ayı Aidat, Kira vb.)")        if st.button("İşlemi Kasaya Kaydet"):            if k_tutar > 0:                new_k = pd.DataFrame([{"Tarih": k_tarih.strftime("%Y-%m-%d"), "Tip": k_tip, "Kategori": k_kat, "Miktar": k_tutar, "Detay": k_detay}])                conn.update(worksheet="kasa", data=pd.concat([df_k, new_k], ignore_index=True))                st.success(f"💰 {k_tarih} tarihli {k_kat} işlemi başarıyla kaydedildi.")            else:                st.warning("Lütfen tutar giriniz.")    # --- 📊 TAB 3: KURUCU RAPORU ---    with t3:        st.header("📊 Günlük Detaylı Rapor")        t_sec = st.date_input("Rapor Tarihi", datetime.now()).strftime("%Y-%m-%d")                try:            dv = conn.read(worksheet="gorusmeler", ttl=0)            dk = conn.read(worksheet="kasa", ttl=0)                        dv['Tarih'] = dv['Tarih'].astype(str)            dk['Tarih'] = dk['Tarih'].astype(str)            dv_b = dv[dv['Tarih'].str.contains(t_sec, na=False)]            dk_b = dk[dk['Tarih'].str.contains(t_sec, na=False)]            dk_b['Miktar'] = pd.to_numeric(dk_b['Miktar'], errors='coerce').fillna(0)                        gelir_df = dk_b[dk_b['Tip'] == 'Gelir (Tahsilat)']            gider_df = dk_b[dk_b['Tip'] == 'Gider (Ödeme)']            t_gelir = gelir_df['Miktar'].sum()            t_gider = gider_df['Miktar'].sum()                        c1, c2, c3, c4 = st.columns(4)            c1.metric("Görüşme", len(dv_b))            c2.metric("Toplam Gelir", f"{t_gelir:,.0f} TL")            c3.metric("Toplam Gider", f"{t_gider:,.0f} TL")            c4.metric("Net Kasa", f"{t_gelir - t_gider:,.0f} TL", delta=float(t_gelir - t_gider))            st.divider()            col_list1, col_list2 = st.columns(2)                        with col_list1:                st.subheader("💰 Gelirler")                if not gelir_df.empty:                    st.dataframe(gelir_df[['Kategori', 'Miktar', 'Detay']], use_container_width=True)                else:                    st.info("Bu tarihte gelir kaydı yok.")                        with col_list2:                st.subheader("💸 Giderler")                if not gider_df.empty:                    st.dataframe(gider_df[['Kategori', 'Miktar', 'Detay']], use_container_width=True)                else:                    st.info("Bu tarihte gider kaydı yok.")            msg = f"*🏫 BOSTANLI ÇÖZÜM VIP RAPORU ({t_sec})*\n\n"            msg += f"*📊 ÖZET*\n📞 Görüşme: {len(dv_b)}\n💰 Gelir: {t_gelir:,.0f} TL\n💸 Gider: {t_gider:,.0f} TL\n📈 Net: {t_gelir - t_gider:,.0f} TL\n\n"                        if not gelir_df.empty:                msg += "*💰 GELİR DETAYLARI*\n"                for _, r in gelir_df.iterrows():                    msg += f"- {r['Kategori']}: {r['Miktar']:,.0f} TL ({r['Detay']})\n"                        if not gider_df.empty:                msg += "\n*💸 GİDER DETAYLARI*\n"                for _, r in gider_df.iterrows():                    msg += f"- {r['Kategori']}: {r['Miktar']:,.0f} TL ({r['Detay']})\n"            if not dv_b.empty:                msg += "\n*📞 GÖRÜŞMELER*\n"                for _, r in dv_b.iterrows():                    msg += f"- {r['Ad Soyad']} ({r['Konu']})\n"            st.divider()            st.markdown(f'[(📲 Raporu WhatsApp ile Gönder)]({wa_link("905492551912", msg)})')        except Exception as e:            st.error(f"Rapor hatası: {e}")    # --- 📈 TAB 4: ANALİZ ---    with t4:        st.header("📈 Finansal Analiz")        try:            dk = conn.read(worksheet="kasa", ttl=0)            dk['Miktar'] = pd.to_numeric(dk['Miktar'], errors='coerce').fillna(0)            dk['Tarih'] = pd.to_datetime(dk['Tarih'], errors='coerce')            dk = dk.dropna(subset=['Tarih'])            col_f1, col_f2 = st.columns(2)            bas_tar = col_f1.date_input("Başlangıç Tarihi", datetime.now() - timedelta(days=90))            bit_tar = col_f2.date_input("Bitiş Tarihi", datetime.now())            mask = (dk['Tarih'].dt.date >= bas_tar) & (dk['Tarih'].dt.date <= bit_tar)            df_filtre = dk.loc[mask]                        if not df_filtre.empty:                c_g1, c_g2 = st.columns(2)                df_gelir_pasta = df_filtre[df_filtre['Tip'] == 'Gelir (Tahsilat)'].groupby('Kategori')['Miktar'].sum().reset_index()                fig_gelir = px.pie(df_gelir_pasta, values='Miktar', names='Kategori', title="💰 Gelir Dağılımı", hole=0.4)                c_g1.plotly_chart(fig_gelir, use_container_width=True)                df_gider_pasta = df_filtre[df_filtre['Tip'] == 'Gider (Ödeme)'].groupby('Kategori')['Miktar'].sum().reset_index()                fig_gider = px.pie(df_gider_pasta, values='Miktar', names='Kategori', title="💸 Gider Dağılımı", hole=0.4)                c_g2.plotly_chart(fig_gider, use_container_width=True)            else: st.warning("Seçilen tarih aralığında veri bulunamadı.")        except Exception as e:            st.error(f"Analiz Hatası: {e}")